import{c as i,Q as e,j as n,m as o}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"Persone Kupaca i Korisnika","description":"Definisanje ključnih persona korisnika i donosilaca odluka za AI Workflow Orchestrator","frontmatter":{"title":"Persone Kupaca i Korisnika","description":"Definisanje ključnih persona korisnika i donosilaca odluka za AI Workflow Orchestrator","keywords":"buyer persona, user persona, target audience, customer profiles","robots":"index, follow"},"headers":[],"relativePath":"personas/index.md","filePath":"personas/index.md","lastUpdated":null}'),s={name:"personas/index.md"};function t(r,a,l,k,u,p){return e(),n("div",null,[...a[0]||(a[0]=[o(`<h1 id="👤-persone-kupaca-i-korisnika" tabindex="-1">👤 Persone Kupaca i Korisnika <a class="header-anchor" href="#👤-persone-kupaca-i-korisnika" aria-label="Permalink to &quot;👤 Persone Kupaca i Korisnika&quot;">​</a></h1><p>Da bismo osigurali da <strong>AI Workflow Orchestrator</strong> rešava stvarne poslovne i tehničke probleme, definisali smo dve ključne persone: <strong>Kupca</strong> (donosioca odluke o kupovini) i <strong>Korisnika</strong> (inženjera koji svakodnevno koristi sistem).</p><hr><h2 id="👔-1-buyer-persona-donosilac-odluke-o-nabavci" tabindex="-1">👔 1. Buyer Persona: Donosilac Odluke o Nabavci <a class="header-anchor" href="#👔-1-buyer-persona-donosilac-odluke-o-nabavci" aria-label="Permalink to &quot;👔 1. Buyer Persona: Donosilac Odluke o Nabavci&quot;">​</a></h2><ul><li><strong>Ime:</strong> Marko Jovanović</li><li><strong>Uloga:</strong> VP of Security &amp; Infrastructure (Potpredsednik za sigurnost i infrastrukturu)</li><li><strong>Kompanija:</strong> Srednja fintech kompanija sa brzim rastom</li><li><strong>Demografija:</strong> 42 godine, magistar elektrotehnike, živi u Beogradu.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  [ MARKO JOVANOVIĆ — VP OF SECURITY ]</span></span>
<span class="line"><span>   Cilj: 100% usklađenost, bezbednost podataka, kontrolisana AI automatizacija.</span></span>
<span class="line"><span>   Bolna tačka: Tradicionalni AI agenti koji slepo izvršavaju skripte i rizikuju curenje podataka.</span></span></code></pre></div><h3 id="ciljevi-i-motivi" tabindex="-1">Ciljevi i Motivi: <a class="header-anchor" href="#ciljevi-i-motivi" aria-label="Permalink to &quot;Ciljevi i Motivi:&quot;">​</a></h3><ul><li><strong>Usklađenost i Auditabilnost:</strong> Zahteva da svaka automatska akcija u oblaku ima jasan i retroaktivno proverljiv &quot;reasoning chain&quot; (lanac razmišljanja) radi PCI-DSS usklađenosti.</li><li><strong>Eliminacija rizika:</strong> Želi sistem koji ne dozvoljava nijednom pojedinačnom AI agentu da samostalno izvrši kod bez unutrašnjeg preispitivanja i provere.</li><li><strong>Finansijska predvidivost:</strong> Zahteva čvrste limite potrošnje tokena kako bi sprečio finansijska iznenađenja.</li></ul><h3 id="kljucne-bolne-tacke-pain-points" tabindex="-1">Ključne Bolne Tačke (Pain Points): <a class="header-anchor" href="#kljucne-bolne-tacke-pain-points" aria-label="Permalink to &quot;Ključne Bolne Tačke (Pain Points):&quot;">​</a></h3><ul><li><strong>Strah od curenja podataka:</strong> Ne veruje standardnim &quot;black-box&quot; agentima koji mogu poslati osetljive podatke kompanije spoljnim LLM provajderima.</li><li><strong>Nebezbedne konfiguracije:</strong> Ranija negativna iskustva sa AI kod generisanjem koje je kreiralo privilegovane Kubernetes kontejnere sa otvorenim portovima.</li></ul><hr><h2 id="👩‍💻-2-user-persona-svakodnevni-korisnik" tabindex="-1">👩‍💻 2. User Persona: Svakodnevni Korisnik <a class="header-anchor" href="#👩‍💻-2-user-persona-svakodnevni-korisnik" aria-label="Permalink to &quot;👩‍💻 2. User Persona: Svakodnevni Korisnik&quot;">​</a></h2><ul><li><strong>Ime:</strong> Jelena Nikolić</li><li><strong>Uloga:</strong> Lead DevOps &amp; Site Reliability Engineer (SRE)</li><li><strong>Kompanija:</strong> Isti fintech startup</li><li><strong>Demografija:</strong> 29 godina, inženjer informacionih tehnologija, živi u Novom Sadu.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                   [ JELENA NIKOLIĆ — LEAD SRE ]</span></span>
<span class="line"><span>   Cilj: Brza orkestracija, bezbedni planovi, automatsko otklanjanje kvarova.</span></span>
<span class="line"><span>   Bolna tačka: Ručno popravljanje sitnih grešaka u konfiguracionim skriptama.</span></span></code></pre></div><h3 id="ciljevi-i-motivi-1" tabindex="-1">Ciljevi i Motivi: <a class="header-anchor" href="#ciljevi-i-motivi-1" aria-label="Permalink to &quot;Ciljevi i Motivi:&quot;">​</a></h3><ul><li><strong>Brza automatizacija:</strong> Želi da delegira kompleksne zadatke (poput postavljanja klastera) sistemu koji samostalno piše planove i izvršava ih.</li><li><strong>Smanjenje ručnog rada:</strong> Želi da AI sistem sam dijagnostikuje i ispravi sitne greške pri podizanju sistema bez njenog učešća (Self-Healing).</li><li><strong>Jednostavna integracija:</strong> Zahteva čist REST API i SSE strimovanje stanja kako bi integrisala sistem sa postojećim Slack botovima.</li></ul><h3 id="kljucne-bolne-tacke-pain-points-1" tabindex="-1">Ključne Bolne Tačke (Pain Points): <a class="header-anchor" href="#kljucne-bolne-tacke-pain-points-1" aria-label="Permalink to &quot;Ključne Bolne Tačke (Pain Points):&quot;">​</a></h3><ul><li><strong>Umnožavanje grešaka:</strong> Gubitak vremena na analizu logova kada AI skripta pukne na produkciji.</li><li><strong>Komplikovano debugovanje:</strong> Teškoća u praćenju istorijskih odluka koje su dovele do trenutnog stanja infrastrukture.</li></ul>`,18)])])}const v=i(s,[["render",t]]);export{c as __pageData,v as default};
